var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"윽...... 크으......","JPN":"うっ……くっ……","ENG":"Ugh... Gah...","TWN":"呃……唔……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_EARTHQUAKE"},{"id":"L3_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"항상 당신에게는 맛있는 냄새가 났어요, 리벳.","JPN":"いつもあなたからは美味しそうな匂いがしていたんですよ、リベット。","ENG":"We've always felt that you smelled delicious, Rivet.","TWN":"妳身上一直有很美味的味道，里維。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"당신의 오랜 용병 생활로 쌓은 지식이라면...... 분명 제 허기를 달래주겠지요?","JPN":"あなたの長い傭兵生活で積み重ねた知識ならば……きっと我々の飢えも満たされますよね？","ENG":"The amount of knowledge you've accumulated while working as a mercenary will be more than enough to fill our stomach.","TWN":"如果是妳長年的傭兵生活所累積的知識……一定能滿足我的飢餓感吧？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그...... 그만둬요, 에델!","JPN":"や……やめてください、エデル！","ENG":"S- stop it, Edel!","TWN":"住……住手，艾瑟兒！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"네? 레지나 님, 어째서요?","JPN":"え？　レジーナ様、なぜです？","ENG":"I'm sorry? Why should I, Miss Regina?","TWN":"咦？蕾佳娜大人，怎麼了嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"어째서라뇨! 그, 리벳은 당신이 고용한 동료잖아요!","JPN":"なぜですって！？　だって、リベットはあなたが雇った仲間でしょう！","ENG":"What do you mean, why? Rivet is a colleague that you hired yourself!","TWN":"什麼怎麼了！那個，里維不是妳雇傭的夥伴嗎！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"저도 아쉬워요. 하지만 아이들이 이렇게 보채고 있는 걸요?","JPN":"我々も残念です。ですが、この子たちがこんなに食べたがっているので……","ENG":"It's not like I don't feel sorry, but the babies are crying from hunger.","TWN":"我也很遺憾，但是孩子們正纏著我呢？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그게 무슨 상관이에요! 배가 고프다고 동료를 잡아 먹으면 어떻게 해!","JPN":"それがどうしたというのですか！　空腹だからと仲間を食べるなんて！","ENG":"I don't care! You don't eat your colleague just because you're hungry!","TWN":"和這個有什麼關係啊！因為肚子餓就想把同伴抓來吃，妳是想怎樣啊！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"레지나 님답지 않게 비논리적이시네요. 제가 멈춰야 할 이유를 찾을 수가 없는 걸요.","JPN":"レジーナ様らしくない非論理的思考ですね。我々が食べてはならない理由が見つかりませんが。","ENG":"It's not like you to be so unreasonable, Miss Regina. There is not a single reason we'd have to stop.","TWN":"這不合邏輯，真不像蕾佳娜大人。我們找不到自己必須停下的理由。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그, 그럼......","JPN":"じゃ、じゃあ……","ENG":"W-well, then...","TWN":"那、那麼……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"차, 차기 학회장으로서......!","JPN":"じ、次期学会長として……！","ENG":"A-as the next President of the Society!","TWN":"我、我作為下一任學會長……！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"네......?","JPN":"えっ……？","ENG":"Huh?","TWN":"什麼……?"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"차기 학회장으로서 정식으로 요청하겠어요!","JPN":"次期学会長として正式に要請します！","ENG":"As the next President of the Society, I'd like to make a formal request!","TWN":"我作為下一任學會長正式提出要求！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"리벳을 풀어주세요!!","JPN":"リベットを放してください！！","ENG":"Let Rivet go!","TWN":"請放開里維！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"레지나 님의 뜻을 정말 정말 이해하기 어렵네요.","JPN":"レジーナ様の意図は本当に理解できませんね。","ENG":"It's really hard to know what you have in mind, Miss Regina.","TWN":"要理解蕾佳娜大人的意思真的很困難呢。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"하지만 레지나 님께서 학회를 이어주시겠다면야 기꺼이 말씀대로......","JPN":"ですが、レジーナ様が学会を継いでくださるのならば、喜んでおっしゃるとおりに……","ENG":"But if you're really willing to take over the Society, we'll gladly let—","TWN":"不過，既然蕾佳娜大人願意繼任學會長，那我們很樂意聽從……"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"아자, 빈틈!","JPN":"よっしゃ、隙あり！","ENG":"Ta! You're off guard!","TWN":"很好，有破綻！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"아......?!","JPN":"あ……！？","ENG":"Oh?","TWN":"啊……？！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_HIT_BIG"},{"id":"L24_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"리벳!","JPN":"リベット！","ENG":"Rivet!","TWN":"里維！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"리벳, 괜찮아요? 일어설 수 있겠어요?","JPN":"リベット、大丈夫ですか？　立てますか？","ENG":"Are you okay, Rivet? Can you stand?","TWN":"里維，妳沒事吧？能站起來嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"으윽...... 온 몸이 쑤시긴 하네.","JPN":"うぅっ……全身が痛むけどね。","ENG":"Hngh... My whole body's aching.","TWN":"唔……全身刺痛就是了。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L29_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그래도 지금은 엄살피지 말고 계약을 수행해야 할 때라서 말이지.","JPN":"それでも今は頑張って契約を遂行しないと。","ENG":"But this is exactly what my contract obligates me to do.","TWN":"不過現在比起大驚小怪，得先履行契約才行。"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"계약?","JPN":"契約？","ENG":"Your contract?","TWN":"契約？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"당신은 프리드웬 때문에 고용된 거 아니었나요?","JPN":"あなたはプリドウェンの件で雇われたのでは？","ENG":"Didn't you say you were hired to deal with the Prydwen Institution?","TWN":"妳不是因為普利多溫機關才被雇傭的嗎？"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"미안! 내 혓바닥은 싸우면서 주절거릴 만큼 빠르지 않거든!","JPN":"ごめん！　アタシって戦いながらおしゃべりできるほど器用じゃないの！","ENG":"Sorry, I'm not good enough of a multitasker to talk while fighting.","TWN":"抱歉！我的嘴巴沒有快到能邊戰鬥邊嘮叨！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"에델이 움직이지 못하게 붙잡아 줘! 뒷일은 내가 맡을 테니까!","JPN":"エデルが動けないように捕まえてて！　後のことはアタシに任せて！","ENG":"Hold Edel so she doesn't move. I'll take care of the rest.","TWN":"幫我抓住艾瑟兒，別讓她動！後面的事情就交給我了！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아, 알겠습니다!","JPN":"わ、わかりました！","ENG":"O-okay.","TWN":"好，我知道了！"},"stage":{"bg":"CORRIDOR","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}}]`);export{e as default};